 1→export interface LoanInput {
 2→  id: string;
 3→  principal: number;
 4→  annualRate: number;
 5→  emi: number;
 6→  emiDebitDay: number; // 1-28
 7→  startDate: string; // ISO date string (YYYY-MM-DD)
 8→}
 9→
10→export interface PrePayment {
11→  id: string;
12→  date: string; // ISO date string
13→  amount: number;
14→}
15→
16→export interface RateChange {
17→  id: string;
18→  date: string; // ISO date string - effective from this month
19→  newRate: number; // new annual rate %
20→}
21→
22→export interface AmortizationRow {
23→  month: number;
24→  date: string;
25→  openingBalance: number;
26→  interestComponent: number;
27→  principalComponent: number;
28→  prePayment: number;
29→  totalPayment: number;
30→  closingBalance: number;
31→  annualRate: number; // effective rate for this month
32→}
33→
34→export interface AmortizationResult {
35→  schedule: AmortizationRow[];
36→  totalInterest: number;
37→  totalAmountPaid: number;
38→  closureDate: string;
39→  totalMonths: number;
40→}
41→
42→export interface LoanSummary {
43→  withPrePayments: AmortizationResult;
44→  withoutPrePayments: AmortizationResult;
45→  interestSaved: number;
46→  monthsSaved: number;
