  1→import { addMonths, format, parseISO, lastDayOfMonth, min } from 'date-fns';
  2→import type {
  3→  LoanInput,
  4→  PrePayment,
  5→  RateChange,
  6→  AmortizationRow,
  7→  AmortizationResult,
  8→  LoanSummary,
  9→} from '../types/loan';
 10→
 11→function getEmiDate(year: number, month: number, emiDay: number): Date {
 12→  const date = new Date(year, month, 1);
 13→  const lastDay = lastDayOfMonth(date).getDate();
 14→  const day = Math.min(emiDay, lastDay);
 15→  return new Date(year, month, day);
 16→}
 17→
 18→function groupPrePaymentsByMonth(
 19→  prePayments: PrePayment[]
 20→): Map<string, number> {
 21→  const map = new Map<string, number>();
 22→  for (const pp of prePayments) {
 23→    const key = format(parseISO(pp.date), 'yyyy-MM');
 24→    map.set(key, (map.get(key) || 0) + pp.amount);
 25→  }
 26→  return map;
 27→}
 28→
 29→function buildRateByMonth(
 30→  rateChanges: RateChange[]
 31→): Map<string, number> {
 32→  const map = new Map<string, number>();
 33→  for (const rc of rateChanges) {
 34→    const key = format(parseISO(rc.date), 'yyyy-MM');
 35→    map.set(key, rc.newRate); // last one wins if multiple in same month
 36→  }
 37→  return map;
 38→}
 39→
 40→export function calculateAmortization(
 41→  loan: LoanInput,
 42→  prePayments: PrePayment[],
 43→  rateChanges: RateChange[] = []
 44→): AmortizationResult {
 45→  let currentAnnualRate = loan.annualRate;
 46→  let monthlyRate = currentAnnualRate / 100 / 12;
 47→  const ppByMonth = groupPrePaymentsByMonth(prePayments);
 48→  // Sort rate changes by date and build lookup
 49→  const sortedRateChanges = [...rateChanges].sort(
 50→    (a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()
 51→  );
 52→  const rateByMonth = buildRateByMonth(sortedRateChanges);
 53→
 54→  const startDate = parseISO(loan.startDate);
 55→  let outstanding = loan.principal;
 56→  const schedule: AmortizationRow[] = [];
 57→  let totalInterest = 0;
 58→  let totalPaid = 0;
 59→  let monthNum = 0;
 60→  let currentDate = getEmiDate(
 61→    startDate.getFullYear(),
 62→    startDate.getMonth(),
 63→    loan.emiDebitDay
 64→  );
 65→
 66→  // If start date is after the emi day in that month, move to next month
 67→  if (currentDate < startDate) {
 68→    currentDate = addMonths(currentDate, 1);
 69→    currentDate = getEmiDate(
 70→      currentDate.getFullYear(),
 71→      currentDate.getMonth(),
 72→      loan.emiDebitDay
 73→    );
 74→  }
 75→
 76→  const MAX_MONTHS = 600;
 77→
 78→  while (outstanding > 0.01 && monthNum < MAX_MONTHS) {
 79→    monthNum++;
 80→    const dateStr = format(currentDate, 'yyyy-MM-dd');
 81→    const monthKey = format(currentDate, 'yyyy-MM');
 82→    const openingBalance = outstanding;
 83→
 84→    // Check for rate change this month
 85→    const newRate = rateByMonth.get(monthKey);
 86→    if (newRate !== undefined) {
 87→      currentAnnualRate = newRate;
 88→      monthlyRate = currentAnnualRate / 100 / 12;
 89→    }
 90→
 91→    const interest = outstanding * monthlyRate;
 92→    let principalPortion: number;
 93→    let emiPaid: number;
 94→
 95→    if (outstanding + interest <= loan.emi) {
 96→      // Final partial EMI
 97→      emiPaid = outstanding + interest;
 98→      principalPortion = outstanding;
 99→    } else {
100→      emiPaid = loan.emi;
101→      principalPortion = loan.emi - interest;
102→    }
103→
104→    outstanding -= principalPortion;
105→    totalInterest += interest;
106→    totalPaid += emiPaid;
107→
108→    // Apply pre-payment after EMI
109→    let ppAmount = 0;
110→    const scheduledPP = ppByMonth.get(monthKey) || 0;
111→    if (scheduledPP > 0 && outstanding > 0.01) {
112→      ppAmount = Math.min(scheduledPP, outstanding);
113→      outstanding -= ppAmount;
114→      totalPaid += ppAmount;
115→    }
116→
117→    // Round near-zero to zero
118→    if (outstanding < 0.01) outstanding = 0;
119→
120→    schedule.push({
121→      month: monthNum,
122→      date: dateStr,
123→      openingBalance: Math.round(openingBalance * 100) / 100,
124→      interestComponent: Math.round(interest * 100) / 100,
125→      principalComponent: Math.round(principalPortion * 100) / 100,
126→      prePayment: Math.round(ppAmount * 100) / 100,
127→      totalPayment: Math.round((emiPaid + ppAmount) * 100) / 100,
128→      closingBalance: Math.round(outstanding * 100) / 100,
129→      annualRate: currentAnnualRate,
130→    });
131→
132→    if (outstanding <= 0) break;
133→
134→    // Advance to next month
135→    currentDate = addMonths(currentDate, 1);
136→    currentDate = getEmiDate(
137→      currentDate.getFullYear(),
138→      currentDate.getMonth(),
139→      loan.emiDebitDay
140→    );
141→  }
142→
143→  const lastRow = schedule[schedule.length - 1];
144→  return {
145→    schedule,
146→    totalInterest: Math.round(totalInterest * 100) / 100,
147→    totalAmountPaid: Math.round(totalPaid * 100) / 100,
148→    closureDate: lastRow?.date || loan.startDate,
149→    totalMonths: schedule.length,
150→  };
151→}
152→
153→export function generateSummary(
154→  loan: LoanInput,
155→  prePayments: PrePayment[],
156→  rateChanges: RateChange[] = []
157→): LoanSummary {
158→  const withPrePayments = calculateAmortization(loan, prePayments, rateChanges);
159→  const withoutPrePayments = calculateAmortization(loan, [], rateChanges);
160→
161→  return {
162→    withPrePayments,
163→    withoutPrePayments,
164→    interestSaved:
165→      Math.round(
166→        (withoutPrePayments.totalInterest - withPrePayments.totalInterest) * 100
167→      ) / 100,
168→    monthsSaved: withoutPrePayments.totalMonths - withPrePayments.totalMonths,
169→  };
170→}
171→
172→export function validateLoan(loan: LoanInput): string | null {
173→  if (loan.principal <= 0) return 'Principal must be positive';
174→  if (loan.annualRate <= 0 || loan.annualRate > 50)
175→    return 'Interest rate must be between 0 and 50%';
176→  if (loan.emi <= 0) return 'EMI must be positive';
177→  if (loan.emiDebitDay < 1 || loan.emiDebitDay > 28)
178→    return 'EMI debit day must be between 1 and 28';
179→
180→  const firstMonthInterest = loan.principal * (loan.annualRate / 100 / 12);
181→  if (loan.emi <= firstMonthInterest) {
182→    return `EMI (${loan.emi}) must exceed first month's interest (${Math.round(firstMonthInterest)}) to repay the loan`;
183→  }
184→
185→  return null;
186→}
