 1→import type { LoanInput, PrePayment, RateChange } from '../types/loan';
 2→
 3→const STORAGE_KEY = 'loan-analyser-state';
 4→
 5→export interface StoredState {
 6→  loan: LoanInput | null;
 7→  prePayments: PrePayment[];
 8→  rateChanges: RateChange[];
 9→}
10→
11→export function loadState(): StoredState {
12→  try {
13→    const raw = localStorage.getItem(STORAGE_KEY);
14→    if (!raw) return { loan: null, prePayments: [], rateChanges: [] };
15→    const parsed = JSON.parse(raw);
16→    return { loan: null, prePayments: [], rateChanges: [], ...parsed } as StoredState;
17→  } catch {
18→    return { loan: null, prePayments: [], rateChanges: [] };
19→  }
20→}
21→
22→export function saveState(state: StoredState): void {
23→  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
24→}
