import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ReferenceLine,
} from 'recharts';
import { format } from 'date-fns';
import type { LoanSummary } from '../../types/loan';
import { formatCurrency, formatDate } from '../../utils/formatters';

interface Props {
  summary: LoanSummary;
}

export function BalanceChart({ summary }: Props) {
  const { withPrePayments, withoutPrePayments } = summary;

  const currentMonthKey = format(new Date(), 'yyyy-MM');

  const maxLen = Math.max(
    withPrePayments.schedule.length,
    withoutPrePayments.schedule.length
  );

  let currentMonthIndex: number | null = null;

  const data = Array.from({ length: maxLen }, (_, i) => {
    const dateStr =
      withoutPrePayments.schedule[i]?.date ??
      withPrePayments.schedule[i]?.date ??
      '';
    const monthKey = dateStr.substring(0, 7);
    if (monthKey === currentMonthKey) {
      currentMonthIndex = i + 1;
    }
    return {
      month: i + 1,
      label: dateStr ? formatDate(dateStr) : '',
      withoutPP: withoutPrePayments.schedule[i]?.closingBalance ?? 0,
      withPP: withPrePayments.schedule[i]?.closingBalance ?? 0,
    };
  });

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h3 className="mb-4 text-lg font-semibold text-gray-900">
        Outstanding Balance Over Time
      </h3>
      <ResponsiveContainer width="100%" height={350}>
        <LineChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis
            dataKey="month"
            label={{ value: 'Month', position: 'insideBottom', offset: -5 }}
          />
          <YAxis
            tickFormatter={(v) => formatCurrency(v)}
            width={100}
          />
          <Tooltip
            formatter={(value: number) => formatCurrency(value)}
            labelFormatter={(label) => `Month ${label}`}
          />
          <Legend />
          {currentMonthIndex !== null && (
            <ReferenceLine
              x={currentMonthIndex}
              stroke="#2563eb"
              strokeWidth={2}
              strokeDasharray="4 4"
              label={{ value: 'Now', position: 'top', fill: '#2563eb', fontWeight: 'bold' }}
            />
          )}
          <Line
            type="monotone"
            dataKey="withoutPP"
            name="Without Pre-Payments"
            stroke="#94a3b8"
            strokeWidth={2}
            dot={false}
          />
          <Line
            type="monotone"
            dataKey="withPP"
            name="With Pre-Payments"
            stroke="#2563eb"
            strokeWidth={2}
            dot={false}
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  Cell,
} from 'recharts';
import type { LoanSummary } from '../../types/loan';
import { formatCurrency } from '../../utils/formatters';

interface Props {
  summary: LoanSummary;
}

export function ComparisonChart({ summary }: Props) {
  const { withPrePayments: wp, withoutPrePayments: wop } = summary;

  const data = [
    {
      name: 'Total Interest',
      'Without Pre-Payments': wop.totalInterest,
      'With Pre-Payments': wp.totalInterest,
    },
    {
      name: 'Total Paid',
      'Without Pre-Payments': wop.totalAmountPaid,
      'With Pre-Payments': wp.totalAmountPaid,
    },
  ];

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h3 className="mb-4 text-lg font-semibold text-gray-900">
        With vs Without Pre-Payments
      </h3>
      <ResponsiveContainer width="100%" height={350}>
        <BarChart data={data} barCategoryGap="30%">
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis tickFormatter={(v) => formatCurrency(v)} width={100} />
          <Tooltip formatter={(value: number) => formatCurrency(value)} />
          <Legend />
          <Bar dataKey="Without Pre-Payments" fill="#94a3b8" />
          <Bar dataKey="With Pre-Payments" fill="#2563eb" />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}

