import { useLoanData } from './hooks/useLoanData';
import { useAmortization } from './hooks/useAmortization';
import { LoanForm } from './components/LoanForm';
import { PrePaymentList } from './components/PrePaymentList';
import { RateChangeList } from './components/RateChangeList';
import { SummaryCards } from './components/SummaryCards';
import { AmortizationTable } from './components/AmortizationTable';
import { WhatIfSimulator } from './components/WhatIfSimulator';
import { BalanceChart } from './components/charts/BalanceChart';
import { PrincipalInterestChart } from './components/charts/PrincipalInterestChart';
import { ComparisonChart } from './components/charts/ComparisonChart';

function App() {
  const {
    loan, setLoan,
    prePayments, addPrePayment, removePrePayment,
    rateChanges, addRateChange, removeRateChange,
  } = useLoanData();
  const { summary, error } = useAmortization(loan, prePayments, rateChanges);

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="border-b border-gray-200 bg-white">
        <div className="mx-auto max-w-7xl px-4 py-4">
          <h1 className="text-2xl font-bold text-gray-900">Loan Analyser</h1>
          <p className="text-sm text-gray-500">
            Visualise your loan, add pre-payments, and see how much you save
          </p>
        </div>
      </header>

      <main className="mx-auto max-w-7xl px-4 py-6 space-y-6">
        <LoanForm loan={loan} onSubmit={setLoan} />

        {error && (
          <div className="rounded-xl border border-red-200 bg-red-50 p-4 text-sm text-red-700">
            {error}
          </div>
        )}

        {loan && (
          <>
            <PrePaymentList
              prePayments={prePayments}
              onAdd={addPrePayment}
              onRemove={removePrePayment}
            />
            <RateChangeList
              rateChanges={rateChanges}
              onAdd={addRateChange}
              onRemove={removeRateChange}
            />
          </>
        )}

        {summary && (
          <>
            <SummaryCards summary={summary} />

            <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
              <BalanceChart summary={summary} />
              <ComparisonChart summary={summary} />
            </div>

            <PrincipalInterestChart
              schedule={summary.withPrePayments.schedule}
            />

            <AmortizationTable
              schedule={summary.withPrePayments.schedule}
            />
          </>
        )}
      </main>
    </div>
  );
}

export default App;

import type { LoanSummary } from '../types/loan';
import { formatCurrency, formatDate } from '../utils/formatters';

interface Props {
  summary: LoanSummary;
}

export function SummaryCards({ summary }: Props) {
  const { withPrePayments: wp, withoutPrePayments: wop } = summary;

  const cards = [
    {
      label: 'Total Interest',
      value: formatCurrency(wp.totalInterest),
      sub: `Without pre-payments: ${formatCurrency(wop.totalInterest)}`,
      color: 'bg-red-50 border-red-200',
    },
    {
      label: 'Total Amount Paid',
      value: formatCurrency(wp.totalAmountPaid),
      sub: `Without pre-payments: ${formatCurrency(wop.totalAmountPaid)}`,
      color: 'bg-blue-50 border-blue-200',
    },
    {
      label: 'Loan Closure Date',
      value: formatDate(wp.closureDate),
      sub: `Without pre-payments: ${formatDate(wop.closureDate)}`,
      color: 'bg-purple-50 border-purple-200',
    },
    {
      label: 'Interest Saved',
      value: formatCurrency(summary.interestSaved),
      sub: `${((summary.interestSaved / wop.totalInterest) * 100).toFixed(1)}% reduction`,
      color: 'bg-green-50 border-green-200',
    },
    {
      label: 'Months Saved',
      value: `${summary.monthsSaved} months`,
      sub: `${wp.totalMonths} vs ${wop.totalMonths} months`,
      color: 'bg-amber-50 border-amber-200',
    },
  ];

  return (
    <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-5">
      {cards.map((card) => (
        <div
          key={card.label}
          className={`rounded-xl border p-4 ${card.color}`}
        >
          <p className="text-xs font-medium text-gray-500 uppercase tracking-wide">
            {card.label}
          </p>
          <p className="mt-1 text-xl font-bold text-gray-900">{card.value}</p>
          <p className="mt-1 text-xs text-gray-500">{card.sub}</p>
        </div>
      ))}
    </div>
  );
}

