import { addMonths, format, parseISO, lastDayOfMonth, min } from 'date-fns';
import type {
  LoanInput,
  PrePayment,
  RateChange,
  AmortizationRow,
  AmortizationResult,
  LoanSummary,
} from '../types/loan';

function getEmiDate(year: number, month: number, emiDay: number): Date {
  const date = new Date(year, month, 1);
  const lastDay = lastDayOfMonth(date).getDate();
  const day = Math.min(emiDay, lastDay);
  return new Date(year, month, day);
}

function groupPrePaymentsByMonth(
  prePayments: PrePayment[]
): Map<string, number> {
  const map = new Map<string, number>();
  for (const pp of prePayments) {
    const key = format(parseISO(pp.date), 'yyyy-MM');
    map.set(key, (map.get(key) || 0) + pp.amount);
  }
  return map;
}

function buildRateByMonth(
  rateChanges: RateChange[]
): Map<string, number> {
  const map = new Map<string, number>();
  for (const rc of rateChanges) {
    const key = format(parseISO(rc.date), 'yyyy-MM');
    map.set(key, rc.newRate); // last one wins if multiple in same month
  }
  return map;
}

export function calculateAmortization(
  loan: LoanInput,
  prePayments: PrePayment[],
  rateChanges: RateChange[] = []
): AmortizationResult {
  let currentAnnualRate = loan.annualRate;
  let monthlyRate = currentAnnualRate / 100 / 12;
  const ppByMonth = groupPrePaymentsByMonth(prePayments);
  // Sort rate changes by date and build lookup
  const sortedRateChanges = [...rateChanges].sort(
    (a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()
  );
  const rateByMonth = buildRateByMonth(sortedRateChanges);

  const startDate = parseISO(loan.startDate);
  let outstanding = loan.principal;
  const schedule: AmortizationRow[] = [];
  let totalInterest = 0;
  let totalPaid = 0;
  let monthNum = 0;
  let currentDate = getEmiDate(
    startDate.getFullYear(),
    startDate.getMonth(),
    loan.emiDebitDay
  );

  // If start date is after the emi day in that month, move to next month
  if (currentDate < startDate) {
    currentDate = addMonths(currentDate, 1);
    currentDate = getEmiDate(
      currentDate.getFullYear(),
      currentDate.getMonth(),
      loan.emiDebitDay
    );
  }

  const MAX_MONTHS = 600;

  while (outstanding > 0.01 && monthNum < MAX_MONTHS) {
    monthNum++;
    const dateStr = format(currentDate, 'yyyy-MM-dd');
    const monthKey = format(currentDate, 'yyyy-MM');
    const openingBalance = outstanding;

    // Check for rate change this month
    const newRate = rateByMonth.get(monthKey);
    if (newRate !== undefined) {
      currentAnnualRate = newRate;
      monthlyRate = currentAnnualRate / 100 / 12;
    }

    const interest = outstanding * monthlyRate;
    let principalPortion: number;
    let emiPaid: number;

    if (outstanding + interest <= loan.emi) {
      // Final partial EMI
      emiPaid = outstanding + interest;
      principalPortion = outstanding;
    } else {
      emiPaid = loan.emi;
      principalPortion = loan.emi - interest;
    }

    outstanding -= principalPortion;
    totalInterest += interest;
    totalPaid += emiPaid;

    // Apply pre-payment after EMI
    let ppAmount = 0;
    const scheduledPP = ppByMonth.get(monthKey) || 0;
    if (scheduledPP > 0 && outstanding > 0.01) {
      ppAmount = Math.min(scheduledPP, outstanding);
      outstanding -= ppAmount;
      totalPaid += ppAmount;
    }

    // Round near-zero to zero
    if (outstanding < 0.01) outstanding = 0;

    schedule.push({
      month: monthNum,
      date: dateStr,
      openingBalance: Math.round(openingBalance * 100) / 100,
      interestComponent: Math.round(interest * 100) / 100,
      principalComponent: Math.round(principalPortion * 100) / 100,
      prePayment: Math.round(ppAmount * 100) / 100,
      totalPayment: Math.round((emiPaid + ppAmount) * 100) / 100,
      closingBalance: Math.round(outstanding * 100) / 100,
      annualRate: currentAnnualRate,
    });

    if (outstanding <= 0) break;

    // Advance to next month
    currentDate = addMonths(currentDate, 1);
    currentDate = getEmiDate(
      currentDate.getFullYear(),
      currentDate.getMonth(),
      loan.emiDebitDay
    );
  }

  const lastRow = schedule[schedule.length - 1];
  return {
    schedule,
    totalInterest: Math.round(totalInterest * 100) / 100,
    totalAmountPaid: Math.round(totalPaid * 100) / 100,
    closureDate: lastRow?.date || loan.startDate,
    totalMonths: schedule.length,
  };
}

export function generateSummary(
  loan: LoanInput,
  prePayments: PrePayment[],
  rateChanges: RateChange[] = []
): LoanSummary {
  const withPrePayments = calculateAmortization(loan, prePayments, rateChanges);
  const withoutPrePayments = calculateAmortization(loan, [], rateChanges);

  return {
    withPrePayments,
    withoutPrePayments,
    interestSaved:
      Math.round(
        (withoutPrePayments.totalInterest - withPrePayments.totalInterest) * 100
      ) / 100,
    monthsSaved: withoutPrePayments.totalMonths - withPrePayments.totalMonths,
  };
}

export function validateLoan(loan: LoanInput): string | null {
  if (loan.principal <= 0) return 'Principal must be positive';
  if (loan.annualRate <= 0 || loan.annualRate > 50)
    return 'Interest rate must be between 0 and 50%';
  if (loan.emi <= 0) return 'EMI must be positive';
  if (loan.emiDebitDay < 1 || loan.emiDebitDay > 28)
    return 'EMI debit day must be between 1 and 28';

  const firstMonthInterest = loan.principal * (loan.annualRate / 100 / 12);
  if (loan.emi <= firstMonthInterest) {
    return `EMI (${loan.emi}) must exceed first month's interest (${Math.round(firstMonthInterest)}) to repay the loan`;
  }

  return null;
}

import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import type { AmortizationRow } from '../../types/loan';
import { formatCurrency } from '../../utils/formatters';

interface Props {
  schedule: AmortizationRow[];
}

export function PrincipalInterestChart({ schedule }: Props) {
  // For large schedules, sample every N months to keep chart readable
  const step = schedule.length > 60 ? Math.ceil(schedule.length / 60) : 1;
  const data = schedule
    .filter((_, i) => i % step === 0 || i === schedule.length - 1)
    .map((row) => ({
      month: row.month,
      principal: row.principalComponent,
      interest: row.interestComponent,
    }));

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h3 className="mb-4 text-lg font-semibold text-gray-900">
        Principal vs Interest per EMI
      </h3>
      <ResponsiveContainer width="100%" height={350}>
        <BarChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="month" />
          <YAxis tickFormatter={(v) => formatCurrency(v)} width={100} />
          <Tooltip formatter={(value: number) => formatCurrency(value)} />
          <Legend />
          <Bar
            dataKey="principal"
            name="Principal"
            stackId="a"
            fill="#22c55e"
          />
          <Bar
            dataKey="interest"
            name="Interest"
            stackId="a"
            fill="#ef4444"
          />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}

import { useState, useMemo } from 'react';
import type { LoanInput, PrePayment, RateChange, AmortizationResult } from '../types/loan';
import { calculateAmortization } from '../utils/amortization';
import { formatCurrency, formatDate, formatDateFull } from '../utils/formatters';

interface Props {
  loan: LoanInput;
  prePayments: PrePayment[];
  rateChanges: RateChange[];
  currentResult: AmortizationResult;
}

export function WhatIfSimulator({ loan, prePayments, rateChanges, currentResult }: Props) {
  const [plannedPPs, setPlannedPPs] = useState<PrePayment[]>([]);
  const [date, setDate] = useState('');
  const [amount, setAmount] = useState('');
  const [isOpen, setIsOpen] = useState(false);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!date || !amount) return;
    setPlannedPPs((prev) => [
      ...prev,
      { id: crypto.randomUUID(), date, amount: Number(amount) },
    ]);
    setDate('');
    setAmount('');
  };

  const handleRemove = (id: string) => {
    setPlannedPPs((prev) => prev.filter((p) => p.id !== id));
  };

  const simulatedResult = useMemo<AmortizationResult | null>(() => {
    if (plannedPPs.length === 0) return null;
    const allPPs = [...prePayments, ...plannedPPs];
    return calculateAmortization(loan, allPPs, rateChanges);
  }, [loan, prePayments, rateChanges, plannedPPs]);

  const impact = useMemo(() => {
    if (!simulatedResult) return null;
    return {
      interestSaved: currentResult.totalInterest - simulatedResult.totalInterest,
      monthsSaved: currentResult.totalMonths - simulatedResult.totalMonths,
      newClosureDate: simulatedResult.closureDate,
      newTotalInterest: simulatedResult.totalInterest,
      newTotalPaid: simulatedResult.totalAmountPaid,
      totalPlanned: plannedPPs.reduce((s, p) => s + p.amount, 0),
    };
  }, [simulatedResult, currentResult, plannedPPs]);

  const sortedPlanned = [...plannedPPs].sort(
    (a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()
  );

  // Default date to next month
  const defaultMinDate = new Date().toISOString().split('T')[0];

  return (
    <div className="rounded-xl border-2 border-dashed border-amber-300 bg-amber-50/50 p-6 shadow-sm">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="flex w-full items-center justify-between"
      >
        <div className="text-left">
          <h2 className="text-lg font-semibold text-gray-900">
            What-If Simulator
          </h2>
          <p className="text-sm text-gray-500">
            Plan future pre-payments and see how they impact your loan
          </p>
        </div>
        <span className="text-2xl text-amber-600">
          {isOpen ? '\u25B2' : '\u25BC'}
        </span>
      </button>

      {isOpen && (
        <div className="mt-5 space-y-5">
          {/* Add planned pre-payment form */}
          <form onSubmit={handleAdd} className="flex flex-wrap items-end gap-3">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Planned Date
              </label>
              <input
                type="date"
                className="rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                min={defaultMinDate}
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Amount (₹)
              </label>
              <input
                type="number"
                className="rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                placeholder="e.g. 500000"
                required
                min="1"
              />
            </div>
            <button
              type="submit"
              className="rounded-lg bg-amber-600 px-4 py-2 text-sm font-medium text-white hover:bg-amber-700"
            >
              Add to Simulation
            </button>
          </form>

          {/* Planned pre-payments list */}
          {sortedPlanned.length > 0 && (
            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead>
